import React from 'react';

const leaderProfiles = [
  { 
    name: 'Mayank Doultani',
    role: 'CEO & Co-Founder',
    desc: 'Driving the vision for Hudson, Mayank combines deep IT consultancy with strategic manpower leadership. His focus is on pioneering industry-specific tech and sourcing.',
    icon: '👤'
  },
  { 
    name: 'Vikas Singh',
    role: 'Technical Director',
    desc: 'Overseeing all software architecture and delivery, Vikas ensures that IT solutions integrate flawlessly with sector requirements. Expert in scalable systems.',
    icon: '⚙️'
  },
];

const Electronics = () => {
  return (
    <section className="py-12 bg-white"> {/* py-24 ko py-12 kiya taaki top/bottom space kam ho */}

      {/* 1. Career Banner - Optimized Space */}
      <div className="max-w-6xl mx-auto px-4 mb-12">
        <div className="bg-orange-50 rounded-[2rem] p-8 md:p-12 text-center border border-orange-100">
          <h1 className="text-3xl md:text-4xl font-black text-gray-900 mb-3 tracking-tighter">
            Start Your Career With Us
          </h1>
          <p className="text-gray-600 mb-6 max-w-xl mx-auto">
            Join our global team and work on industry-leading electronics projects.
          </p>
          <button className="bg-orange-600 text-white px-8 py-3.5 rounded-full font-bold hover:bg-orange-700 shadow-lg shadow-orange-100 transition-all">
            View Current Openings
          </button>
        </div>
      </div>

      {/* 2. Leader Profiles - Tightened Layout */}
      <div className="max-w-6xl mx-auto px-4">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 max-w-5xl mx-auto">
          {leaderProfiles.map((leader, index) => (
            <div 
              key={index} 
              className="flex flex-col p-8 bg-gray-50 border border-gray-100 rounded-[2rem] hover:shadow-md transition-all group"
            >
              <div className="flex items-center gap-5 mb-5">
                <div className="flex-shrink-0 bg-white border border-gray-200 h-16 w-16 rounded-2xl flex items-center justify-center text-3xl text-orange-500 shadow-sm group-hover:scale-105 transition-transform">
                  {leader.icon}
                </div>
                <div>
                  <h4 className="text-xl font-bold text-gray-900 leading-tight">{leader.name}</h4>
                  <p className="text-orange-600 text-xs font-bold uppercase tracking-wider">{leader.role}</p>
                </div>
              </div>

              <p className="text-gray-600 text-sm leading-relaxed">
                {leader.desc}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Electronics;
